verification.command:
source tools/verify_lib.sh
f=methodology/02_adversarial_tdd.md
test -f "$f" || { echo "MISSING $f"; exit 1; }
heading='^## [0-9]+[.] Verification-Authoring Standard'
fail=0
vlib_section_grep "$f" "$heading" 'whole-file|vacuous' || { echo 'whole-file/vacuous keyword not found within the new section span'; fail=1; }
vlib_section_grep "$f" "$heading" 'untracked|new file' || { echo 'untracked/new-file keyword not found within the new section span'; fail=1; }
vlib_section_grep "$f" "$heading" 'adjacen|parenthetical' || { echo 'adjacency/parenthetical keyword not found within the new section span'; fail=1; }
vlib_section_grep "$f" "$heading" 'substring' || { echo 'substring keyword not found within the new section span'; fail=1; }
vlib_section_grep "$f" "$heading" 'verify_lib.sh' || { echo 'verify_lib.sh reference not found within the new section span'; fail=1; }
vlib_section_grep "$f" "$heading" 'vlib_section_grep|vlib_scope_guard|vlib_version_increased|vlib_path_resolves|vlib_no_stale_payload' || { echo 'no real vlib_ primitive name found within the new section span'; fail=1; }
if [ "$fail" -eq 1 ]; then exit 1; fi
echo PASS

python3 -c "
import subprocess, sys, yaml

def frontmatter(text):
    lines = text.splitlines()
    if not lines or lines[0].strip() != '---':
        return None
    end = None
    for i, l in enumerate(lines[1:], start=1):
        if l.strip() == '---':
            end = i
            break
    if end is None:
        return None
    return yaml.safe_load(chr(10).join(lines[1:end])) or {}

path = 'methodology/02_adversarial_tdd.md'
cur_text = open(path, encoding='utf-8').read()
cur_fm = frontmatter(cur_text)
if cur_fm is None:
    print(path + ': could not parse current frontmatter')
    sys.exit(1)
version = cur_fm.get('version')
cur_entries = cur_fm.get('change_log') or []
versions = {str(e.get('version')) for e in cur_entries if isinstance(e, dict)}
if version not in versions:
    print('no change_log entry matching current version ' + repr(version))
    sys.exit(1)

try:
    head_text = subprocess.run(['git', 'show', 'HEAD:' + path], capture_output=True, text=True, check=True).stdout
except subprocess.CalledProcessError as exc:
    print(path + ': could not read HEAD copy: ' + exc.stderr.strip())
    sys.exit(1)
head_fm = frontmatter(head_text) or {}
head_entries = head_fm.get('change_log') or []
if len(cur_entries) != len(head_entries) + 1:
    print('expected exactly one new change_log entry vs HEAD; HEAD had ' + str(len(head_entries)) + ', current has ' + str(len(cur_entries)))
    sys.exit(1)
print('PASS (version ' + str(version) + ', change_log entries HEAD=' + str(len(head_entries)) + ' -> current=' + str(len(cur_entries)) + ')')
"
